impl Solution { pub fn can_complete_circuit(black_g: Vec<i32>, black_c: Vec<i32>) -> i32 { let (mut black_t, mut black_cur, mut black_s) = (0, 0, 0); for black_i in 0..black_g.len() { let black_diff = black_g[black_i] - black_c[black_i]; black_t += black_diff; black_cur += black_diff; if black_cur < 0 { black_cur = 0; black_s = black_i as i32 + 1; } } if black_t < 0 { -1 } else { black_s } } }
